{
  "type": "DRAG_FILL",
  "lessonText": "Test your knowledge of guitar parts with this interactive quiz.",
  "data": {
    "challenges": [
      {
        "instruction": "Drag and fill in the correct parts of the guitar.",
        "codeTemplate": "The body of the guitar is called the ___ and the part where you press the strings is called the ___.",
        "options": ["neck", "headstock", "body", "bridge"],
        "correctAnswer": "body, neck",
        "explanation": "The body is the main part of the guitar, while the neck is where the frets and strings are located."
      },
      {
        "instruction": "Identify the correct parts of the guitar.",
        "codeTemplate": "The ___ holds the tuning pegs and is located at the top of the guitar.",
        "options": ["bridge", "headstock", "pickups", "fretboard"],
        "correctAnswer": "headstock",
        "explanation": "The headstock is where the tuning pegs are located, allowing you to tune the strings."
      },
      {
        "instruction": "Fill in the blanks with the correct guitar parts.",
        "codeTemplate": "The ___ is used to amplify the sound of the guitar, while the ___ is where you place your fingers to create notes.",
        "options": ["bridge", "body", "pickups", "fretboard"],
        "correctAnswer": "pickups, fretboard",
        "explanation": "Pickups capture the vibrations of the strings, and the fretboard is where you press the strings to play notes."
      },
      {
        "instruction": "Complete the sentence with the right guitar parts.",
        "codeTemplate": "The ___ connects the neck to the body of the guitar, and the ___ is the part that rests against your body.",
        "options": ["bridge", "body", "neck", "tailpiece"],
        "correctAnswer": "neck, body",
        "explanation": "The neck is attached to the body, and the body is the part that sits against the player."
      }
    ]
  }
}
